typedef
  enum {Fahrenheit} TempControl_SysVerif_TempUnit;

typedef
  enum {Ok, Error} TempControl_SysVerif_FanAck;

typedef
  enum {On, Off} TempControl_SysVerif_FanCmd;

typedef struct TempControl_SysVerif_Temperature {
  int32_t degrees;
  TempControl_SysVerif_TempUnit unit;
} TempControl_SysVerif_Temperature;

typedef struct TempControl_SysVerif_SetPoint {
  TempControl_SysVerif_Temperature low;
  TempControl_SysVerif_Temperature high;
} TempControl_SysVerif_SetPoint;

#pragma once

#include <stdint.h>

