void sb_queue_TempControl_SysVerif_SetPoint_1_enqueue(
  sb_queue_TempControl_SysVerif_SetPoint_1_t *queue,
  TempControl_SysVerif_SetPoint *data) {

  // Simple ring with one dirty element that will be written next. Only one
  // writer, so no need for any synchronization.
  // elt[queue->numSent % SB_QUEUE_TEMPCONTROL_SYSVERIF_SETPOINT_1_SIZE]
  // is always considered dirty. So do not advance queue->NumSent
  // till AFTER data is copied.

  size_t index = queue->numSent % SB_QUEUE_TEMPCONTROL_SYSVERIF_SETPOINT_1_SIZE;

  queue->elt[index] = *data; // Copy data into queue

