// Receiver API
//
// See sb_queue_TempControl_SysVerif_SetPoint_1.h for API documentation. Only implementation details are documented here.

void sb_queue_TempControl_SysVerif_SetPoint_1_Recv_init(
  sb_queue_TempControl_SysVerif_SetPoint_1_Recv_t *recvQueue,
  sb_queue_TempControl_SysVerif_SetPoint_1_t *queue) {

