verus! {

/** property tc_req_01, bound 'at START' (place START)
  *   loop entry
  */
pub open spec fn sys_assert_tc_req_01_START(st: SystemState) -> bool
{
  ((!st.sv_fanError &&
    (st.sv_latestTemp.degrees < st.sv_currentSetPoint.low.degrees)) ==>
    (st.sv_currentFanState == TempControl_SysVerif::FanCmd::Off)) &&
    ((!st.sv_fanError &&
      (st.sv_latestTemp.degrees > st.sv_currentSetPoint.high.degrees)) ==>
      (st.sv_currentFanState == TempControl_SysVerif::FanCmd::On))
}

/** property tc_req_01, bound 'after sensor' (place after_sensor)
  *   carried across sensor (frame)
  */
pub open spec fn sys_assert_tc_req_01_after_sensor(st: SystemState) -> bool
{
  ((!st.sv_fanError &&
    (st.sv_latestTemp.degrees < st.sv_currentSetPoint.low.degrees)) ==>
    (st.sv_currentFanState == TempControl_SysVerif::FanCmd::Off)) &&
    ((!st.sv_fanError &&
      (st.sv_latestTemp.degrees > st.sv_currentSetPoint.high.degrees)) ==>
      (st.sv_currentFanState == TempControl_SysVerif::FanCmd::On))
}

/** property tc_req_01, bound 'after control' (place after_control)
  *   re-established by control's TC_Req guarantees
  */
pub open spec fn sys_assert_tc_req_01_after_control(st: SystemState) -> bool
{
  (((!st.sv_fanError &&
    (st.sv_latestTemp.degrees < st.sv_currentSetPoint.low.degrees)) ==>
    (st.sv_currentFanState == TempControl_SysVerif::FanCmd::Off)) &&
    ((!st.sv_fanError &&
      (st.sv_latestTemp.degrees > st.sv_currentSetPoint.high.degrees)) ==>
      (st.sv_currentFanState == TempControl_SysVerif::FanCmd::On))) &&
    (st.sensedTemp.is_some() &&
      (!st.sv_fanError &&
        (st.sensedTemp.unwrap().degrees < st.sv_currentSetPoint.low.degrees)) ==>
      (st.sv_currentFanState == TempControl_SysVerif::FanCmd::Off))
}

/** property tc_req_01, bound 'after fan' (place after_fan)
  *   carried across fan (frame)
  */
