static mut app: Option<domain_monitor_process_domain_monitor_thread> = None;
static mut init_api: domain_monitor_process_domain_monitor_thread_Application_Api<domain_monitor_process_domain_monitor_thread_Initialization_Api> = api::init_api();
static mut compute_api: domain_monitor_process_domain_monitor_thread_Application_Api<domain_monitor_process_domain_monitor_thread_Compute_Api> = api::compute_api();

#[no_mangle]
pub extern "C" fn domain_monitor_process_domain_monitor_thread_initialize() {
  logging::init_logging();

  unsafe {
    #[cfg(test)]
    crate::bridge::extern_c_api::initialize_test_globals();

    let mut _app = domain_monitor_process_domain_monitor_thread::new();
    _app.initialize(&mut init_api);
    app = Some(_app);
  }
}

#[no_mangle]
pub extern "C" fn domain_monitor_process_domain_monitor_thread_timeTriggered() {
  unsafe {
    if let Some(_app) = app.as_mut() {
      _app.timeTriggered(&mut compute_api);
    } else {
      panic!("Unexpected: app is None");
    }
  }
}

#[no_mangle]
pub extern "C" fn domain_monitor_process_domain_monitor_thread_notify(channel: microkit_channel) {
  unsafe {
    if let Some(_app) = app.as_mut() {
      _app.notify(channel);
    } else {
      panic!("Unexpected: app is None");
    }
  }
}

// Need a Panic handler in a no_std environment
